SELECT DISTINCT i.id AS id,
       i.row_no AS rowNo,
       i.created_date AS createdDate,
       i.last_updated_date AS lastUpdatedDate
FROM t_eval_dataset_item i
JOIN t_eval_dataset_item_cell c ON c.item_id = i.id
WHERE i.version_id = #{versionId}
  AND i.space_id = #{spaceId}
  AND c.space_id = #{spaceId}
  AND c.field_id = #{fieldId}
  AND c.cell_value LIKE #{like}
ORDER BY i.row_no ASC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(DISTINCT i.id)
FROM t_eval_dataset_item i
JOIN t_eval_dataset_item_cell c ON c.item_id = i.id
WHERE i.version_id = #{versionId}
  AND i.space_id = #{spaceId}
  AND c.space_id = #{spaceId}
  AND c.field_id = #{fieldId}
  AND c.cell_value LIKE #{like}
